def parse_query_string(url):
    # extracting the query string
    query_str = url.split("?")[1]
    query_param = query_str.split("&")

    # create dictionary from query string
    result_dict = {}
    for q in query_param:
        key, value = q.split('=')
        result_dict[key] = value

    return result_dict

