function findWords(str) { 
    let words = []; 
    let start = 0; 

    for (let i = 0; i < str.length; i++) { 
        if (str[i] == ' ') { 
            let word = str.substring(start, i); 
            if (word != '') 
                words.push(word); 
            start = i + 1; 
        } 
    } 

    let lastWord =  str.substring(start, str.length); 
    if (lastWord != '') 
        words.push(lastWord); 

    return words; 
}

