def most_frequent_char(s):
    counts = {}
    max_char = ""
    max_count = 0
    for c in s:
        if c in counts:
            counts[c] += 1
        else:
            counts[c] = 1
        if counts[c] > max_count:
            max_char = c
            max_count = counts[c]
    return max_char

